<template><section class="page vip-page"><van-nav-bar title="VIP 成人内容专区" left-arrow @click-left="$router.back()"/><div v-if="!confirmed" class="gate"><h1>18+ 内容提示</h1><p>本专区仅面向已满 18 周岁的 VIP 用户，可能包含成人主题。</p><van-checkbox v-model="adult">我确认已满 18 周岁并自愿查看</van-checkbox><van-button block type="primary" :disabled="!adult" @click="confirm">确认进入</van-button><van-button block plain @click="$router.replace('/h5/home')">返回免费专区</van-button></div><template v-else><header><small>独立 VIP 内容区</small><h1>{{status.active?'VIP 身份已生效':'当前账号暂无阅读资格'}}</h1><p>专区书籍不会出现在免费首页、分类或搜索中</p></header><div v-if="statusError" class="error">VIP 身份校验失败，请重新登录后重试</div><div v-else-if="!status.active" class="state"><p>普通用户可查看专区书单，但不能阅读 VIP 正文。</p><van-button type="primary" to="/h5/profile">前往“我的”获取资格</van-button></div><van-loading v-if="loading" class="loading"/><div v-else-if="booksError" class="error">VIP 书单加载失败，请稍后重试</div><van-empty v-else-if="!books.length" description="暂无已审批上架的 VIP 书籍"/><div v-else class="books"><button v-for="book in books" :key="book.id" @click="$router.push(`/h5/book/${book.id}`)"><img :src="book.coverUrl||fallback" @error="handleImgError"/><span><b>{{book.title}}</b><small>{{book.author||'佚名'}}</small><em>{{status.active?'VIP 完整阅读':'需要 VIP 资格'}}</em></span></button></div></template></section></template>
<script setup>import{onMounted,ref}from'vue';import{fetchVipBooks,fetchVipStatus}from'../services/vip';import{FALLBACK_COVER,handleImgError}from'../utils/cover';const key='mini_novel_vip_adult_confirmed',adult=ref(false),confirmed=ref(localStorage.getItem(key)==='yes'),loading=ref(false),books=ref([]),status=ref({active:false}),statusError=ref(false),booksError=ref(false),fallback=FALLBACK_COVER;async function load(){loading.value=true;statusError.value=false;booksError.value=false;const results=await Promise.allSettled([fetchVipStatus(),fetchVipBooks()]);if(results[0].status==='fulfilled')status.value=results[0].value;else statusError.value=true;if(results[1].status==='fulfilled')books.value=results[1].value||[];else booksError.value=true;loading.value=false}function confirm(){localStorage.setItem(key,'yes');confirmed.value=true;load()}onMounted(()=>{if(confirmed.value)load()});</script>
<style scoped>.vip-page{min-height:100vh;background:#120f14;color:#f7ecd1}.gate,.state,.error{margin:20px 18px;padding:20px;border-radius:18px;background:#fff;color:#292229}.error{background:#fff1f0;color:#b42318}.gate p{line-height:1.7}.gate .van-checkbox,.gate .van-button{margin-top:18px}header{padding:30px 20px;background:linear-gradient(135deg,#241a28,#76562a)}header h1{margin:8px 0}.loading{display:block;margin:50px auto;text-align:center}.books{padding:16px}.books button{width:100%;display:flex;gap:14px;padding:12px;margin-bottom:12px;border:0;border-radius:14px;text-align:left}.books img{width:72px;height:100px;object-fit:cover;border-radius:8px}.books span{display:flex;flex-direction:column;gap:8px}.books b{font-size:17px}.books em{color:#9b6b22;font-style:normal}</style>
